import React, { useState, useEffect, useRef, useCallback } from 'react';
import { ToolType } from './Toolbar';
import { PuzzleData } from '@/lib/puzzleEncoder';
import { isMob } from '@/lib/utils';

interface PuzzleGridProps {
    puzzleData: PuzzleData;
    playerGrid: number[][]; // 0: empty, 1: filled, 2: crossed, 3: noted
    activeTool: ToolType;
    onApplyCell: (r: number, c: number, v: number) => void;
    onDragEnd: (currentGroup: { r: number, c: number, prev: number }[]) => void;
    clueDoneRows: boolean[];
    clueDoneCols: boolean[];
    isRevealed: boolean;
    hintCell?: { type: 'row' | 'col', index: number } | null;
}

export default function PuzzleGrid({ puzzleData, playerGrid, activeTool, onApplyCell, onDragEnd, clueDoneRows, clueDoneCols, isRevealed, hintCell }: PuzzleGridProps) {
    const { rows, cols, rowClues, colClues } = puzzleData;
    const wrapRef = useRef<HTMLDivElement>(null);
    const [currentZoom, setCurrentZoom] = useState<number>(1);

    // Drag state
    const isDragging = useRef(false);
    const dragState = useRef<number | null>(null);
    const dragAxis = useRef<'row' | 'col' | null>(null);
    const dragStartCell = useRef<{ r: number, c: number } | null>(null);
    const lastTouchedCell = useRef<{ r: number, c: number } | null>(null);
    const currentUndoGroup = useRef<{ r: number, c: number, prev: number }[]>([]);

    const [dimensions, setDimensions] = useState({ CS: 28, W: 0, H: 0, CLW: 28, numW: 14, fs: 11 });

    useEffect(() => {
        const calculateDimensions = () => {
            if (!wrapRef.current || !wrapRef.current.parentElement) return;
            const scrollEl = wrapRef.current.parentElement;
            const avW = (scrollEl.clientWidth || 350) - 24;
            const avH = (scrollEl.clientHeight || 500) - 24;

            const maxRowNums = Math.max(...rowClues.map(r => r.length));
            const maxColNums = Math.max(...colClues.map(c => c.length));

            const CLUE_NUM_W = 14;
            const clueAreaW = maxRowNums * CLUE_NUM_W + 8;
            const clueAreaH = maxColNums * 18 + 4;

            const cellByW = Math.floor((avW - clueAreaW) / cols);
            const cellByH = Math.floor((avH - clueAreaH) / rows);
            const CS = Math.max(18, Math.min(38, cellByW, cellByH)); // cell size
            const CLW = Math.max(CLUE_NUM_W, CS);
            const clueFontSize = Math.max(8, Math.min(11, Math.floor(CLW * 0.5)));

            setDimensions({ CS, W: clueAreaW, H: clueAreaH, CLW, numW: CLUE_NUM_W, fs: clueFontSize });
        };

        calculateDimensions();
        window.addEventListener('resize', calculateDimensions);

        // Auto-fit after a tiny delay to ensure mount dimensions are parsed
        setTimeout(() => {
            if (wrapRef.current && wrapRef.current.parentElement) {
                const scrollEl = wrapRef.current.parentElement;
                const zw = wrapRef.current;
                const wW = scrollEl.clientWidth - 40;
                const wH = scrollEl.clientHeight - 40;
                const gW = zw.scrollWidth;
                const gH = zw.scrollHeight;
                if (gW && gH) {
                    const scale = Math.min(wW / gW, wH / gH, 1);
                    setCurrentZoom(Math.max(isMob() ? 0.4 : 0.8, scale));
                }
            }
        }, 100);

        return () => window.removeEventListener('resize', calculateDimensions);
    }, [cols, rows, rowClues, colClues]);

    const handleDragStart = (r: number, c: number) => {
        let ns = 0;
        if (activeTool === 'fill') ns = playerGrid[r][c] === 1 ? 0 : 1;
        else if (activeTool === 'cross') ns = playerGrid[r][c] === 2 ? 0 : 2;
        else if (activeTool === 'notes') ns = playerGrid[r][c] === 3 ? 0 : 3;

        isDragging.current = true;
        dragState.current = ns;
        dragAxis.current = null;
        dragStartCell.current = { r, c };
        lastTouchedCell.current = { r, c };
        currentUndoGroup.current = [];

        applyToCell(r, c);
    };

    const handleDragMove = (r: number, c: number) => {
        if (!isDragging.current || dragStartCell.current === null || lastTouchedCell.current === null) return;

        if (!dragAxis.current) {
            if (r !== dragStartCell.current.r && c !== dragStartCell.current.c) return;
            if (r !== dragStartCell.current.r) dragAxis.current = 'col';
            else if (c !== dragStartCell.current.c) dragAxis.current = 'row';
        }

        if (dragAxis.current === 'row' && r !== dragStartCell.current.r) return;
        if (dragAxis.current === 'col' && c !== dragStartCell.current.c) return;

        const rStart = Math.min(lastTouchedCell.current.r, r);
        const rEnd = Math.max(lastTouchedCell.current.r, r);
        const cStart = Math.min(lastTouchedCell.current.c, c);
        const cEnd = Math.max(lastTouchedCell.current.c, c);

        for (let i = rStart; i <= rEnd; i++) {
            for (let j = cStart; j <= cEnd; j++) {
                applyToCell(i, j);
            }
        }
        lastTouchedCell.current = { r, c };
    };

    const applyToCell = (r: number, c: number) => {
        if (dragState.current === null || playerGrid[r][c] === dragState.current) return;
        currentUndoGroup.current.push({ r, c, prev: playerGrid[r][c] });
        onApplyCell(r, c, dragState.current);
    };

    const handleDragEnd = useCallback(() => {
        if (!isDragging.current) return;
        isDragging.current = false;
        if (currentUndoGroup.current.length > 0) {
            onDragEnd([...currentUndoGroup.current]);
            currentUndoGroup.current = [];
        }
    }, [onDragEnd]);

    useEffect(() => {
        const handleMouseUp = () => handleDragEnd();
        window.addEventListener('mouseup', handleMouseUp);
        window.addEventListener('touchend', handleMouseUp);
        window.addEventListener('touchcancel', handleMouseUp);
        return () => {
            window.removeEventListener('mouseup', handleMouseUp);
            window.removeEventListener('touchend', handleMouseUp);
            window.removeEventListener('touchcancel', handleMouseUp);
        };
    }, [handleDragEnd]);

    const onTouchMove = (e: React.TouchEvent) => {
        if (!isDragging.current) return;
        // e.preventDefault(); // handled in PuzzlePlayer via css overscroll-none or passive:false ref
        const touch = e.touches[0];
        const target = document.elementFromPoint(touch.clientX, touch.clientY);
        if (!target) return;
        const el = target.closest('.gcell') as HTMLElement;
        if (el) {
            const r = parseInt(el.dataset.r || '0');
            const c = parseInt(el.dataset.c || '0');
            handleDragMove(r, c);
        }
    };

    const zoomIn = () => setCurrentZoom(z => Math.min(3, z + 0.3));
    const zoomOut = () => setCurrentZoom(z => Math.max(isMob() ? 0.4 : 0.8, z - 0.3));

    const maxD = Math.hypot(rows, cols);

    return (
        <div className="flex-1 overflow-auto touch-pan-x touch-pan-y flex justify-center items-start p-[16px_16px_calc(100px+env(safe-area-inset-bottom,0px))]" id="puzzleScrollWrap">
            <div
                ref={wrapRef}
                className="bg-white p-0 inline-block origin-top-left border-2 border-[#b0a89e]"
                style={{ transform: `scale(${currentZoom})` }}
                onContextMenu={e => e.preventDefault()}
            >
                <div className="inline-grid grid-cols-[auto_auto] grid-rows-[auto_auto] select-none text-opacity-100">

                    {/* Corner */}
                    <div
                        className="bg-[#eeebe5] border-r-[2px] border-b-[2px] border-[#b0a89e]"
                        style={{ width: dimensions.W, height: dimensions.H, opacity: isRevealed ? 0.1 : 1 }}
                    />

                    {/* Column Header */}
                    <div className="flex bg-[#eeebe5] border-b-[2px] border-[#b0a89e] items-end" style={{ height: dimensions.H, opacity: isRevealed ? 0.1 : 1 }}>
                        {colClues.map((clue, c) => {
                            const isHint = hintCell?.type === 'col' && hintCell.index === c;
                            return (
                                <div
                                    key={c}
                                    className={`flex flex-col justify-end items-center overflow-hidden ${clueDoneCols[c] ? 'clue-group-done' : ''}`}
                                    style={{
                                        width: dimensions.CLW,
                                        height: dimensions.H,
                                        borderRight: ((c + 1) % 5 === 0 && c < cols - 1) ? '2px solid #b0a89e' : '1px solid #d4cdc5',
                                        background: isHint ? 'rgba(248, 223, 112, 0.6)' : 'transparent'
                                    }}
                                >
                                    {clue.map((n, i) => (
                                        <span key={i} className="col-clue-num font-mono text-[#6b6560] text-center block leading-tight font-medium" style={{ fontSize: dimensions.fs, width: dimensions.CLW, height: 18, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                            {n}
                                        </span>
                                    ))}
                                </div>
                            );
                        })}
                    </div>

                    {/* Row Header */}
                    <div className="flex flex-col bg-[#eeebe5] border-r-[2px] border-[#b0a89e]" style={{ width: dimensions.W, opacity: isRevealed ? 0.1 : 1 }}>
                        {rowClues.map((clue, r) => {
                            const isHint = hintCell?.type === 'row' && hintCell.index === r;
                            return (
                                <div
                                    key={r}
                                    className={`flex flex-row items-center justify-end pr-1 gap-[3px] overflow-hidden ${clueDoneRows[r] ? 'clue-group-done' : ''}`}
                                    style={{
                                        height: dimensions.CS,
                                        width: dimensions.W,
                                        borderBottom: ((r + 1) % 5 === 0 && r < rows - 1) ? '2px solid #b0a89e' : '1px solid #d4cdc5',
                                        background: isHint ? 'rgba(248, 223, 112, 0.6)' : 'transparent'
                                    }}
                                >
                                    {clue.map((n, i) => (
                                        <span key={i} className="row-clue-num font-mono text-[#6b6560] text-right shrink-0 leading-none font-medium" style={{ fontSize: dimensions.fs, minWidth: dimensions.numW }}>
                                            {n}
                                        </span>
                                    ))}
                                </div>
                            );
                        })}
                    </div>

                    {/* Game Grid */}
                    <div
                        className="grid"
                        style={{ gridTemplateColumns: `repeat(${cols}, ${dimensions.CS}px)`, gridTemplateRows: `repeat(${rows}, ${dimensions.CS}px)` }}
                        onMouseDown={e => {
                            const el = (e.target as HTMLElement).closest('.gcell');
                            if (!el) return;
                            const r = parseInt((el as HTMLElement).dataset.r || '0');
                            const c = parseInt((el as HTMLElement).dataset.c || '0');
                            handleDragStart(r, c);
                        }}
                        onMouseOver={e => {
                            const el = (e.target as HTMLElement).closest('.gcell');
                            if (!el) return;
                            const r = parseInt((el as HTMLElement).dataset.r || '0');
                            const c = parseInt((el as HTMLElement).dataset.c || '0');
                            handleDragMove(r, c);
                        }}
                        onTouchStart={e => {
                            if (e.touches.length > 1) { handleDragEnd(); return; }
                            const el = (e.target as HTMLElement).closest('.gcell');
                            if (!el) return;
                            const r = parseInt((el as HTMLElement).dataset.r || '0');
                            const c = parseInt((el as HTMLElement).dataset.c || '0');
                            handleDragStart(r, c);
                        }}
                        onTouchMove={onTouchMove}
                    >
                        {Array.from({ length: rows * cols }).map((_, i) => {
                            const r = Math.floor(i / cols);
                            const c = i % cols;
                            const v = playerGrid[r][c];
                            const isAlt = Math.floor(r / 5) % 2 !== Math.floor(c / 5) % 2;
                            const isDarkRight = (c + 1) % 5 === 0 && c < cols - 1;
                            const isDarkBot = (r + 1) % 5 === 0 && r < rows - 1;

                            // Visual classes
                            let classes = `gcell `;
                            if (isAlt) classes += 'chunk-alt ';
                            if (isDarkRight) classes += 'chunk-dark ';
                            if (isDarkBot) classes += 'chunk-dark-bot ';

                            const popClass = ''; // Pop class requires effect on change, keeping it simple as interaction already feels fine

                            if (v === 1) classes += 'filled ';
                            else if (v === 2) classes += 'crossed ';
                            else if (v === 3) classes += 'noted ';

                            if (isRevealed) classes += 'reveal ';

                            return (
                                <div
                                    key={i}
                                    className={classes}
                                    data-r={r}
                                    data-c={c}
                                    style={{
                                        width: dimensions.CS,
                                        height: dimensions.CS,
                                        fontSize: Math.max(8, Math.floor(dimensions.CS * 0.42)),
                                        // Animation delay for reveal
                                        ['--rd' as any]: isRevealed ? `${Math.hypot(r - rows / 2, c - cols / 2) / maxD * 1.2}s` : '0s'
                                    }}
                                />
                            );
                        })}
                    </div>
                </div>
            </div>

            <div className="absolute bottom-5 right-5 bg-white rounded-[20px] shadow-[0_4px_16px_rgba(0,0,0,0.1)] flex items-center gap-2 px-3 py-1 z-10 transition-opacity">
                <button onClick={zoomOut} className="bg-transparent border-none text-[18px] px-2 py-1 cursor-pointer text-body">-</button>
                <span className="font-mono text-[12px] font-bold w-8 text-center">{(currentZoom).toFixed(1)}x</span>
                <button onClick={zoomIn} className="bg-transparent border-none text-[18px] px-2 py-1 cursor-pointer text-body">+</button>
            </div>
        </div>
    );
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import PuzzleGrid from './PuzzleGrid';
import Toolbar, { ToolType } from './Toolbar';
import RevealAnimation from './RevealAnimation';
import { Toast } from './ui/Toast';
import { PuzzleData } from '@/lib/puzzleEncoder';
import { computeClues } from '@/lib/nonogram';

interface PuzzlePlayerProps {
    puzzleData: PuzzleData;
    onBack: () => void;
}

const safeSave = (key: string, value: string) => {
    try {
        localStorage.setItem(key, value);
    } catch {
        // localStorage blocked (private mode) — continue without saving
    }
};

const safeRemove = (key: string) => {
    try {
        localStorage.removeItem(key);
    } catch { }
};


export default function PuzzlePlayer({ puzzleData, onBack }: PuzzlePlayerProps) {
    const { cols, rows, rowClues, colClues, grid: answerGrid, id } = puzzleData;

    const [playerGrid, setPlayerGrid] = useState<number[][]>(() =>
        Array.from({ length: rows }, () => Array(cols).fill(0))
    );

    const [activeTool, setActiveTool] = useState<ToolType>('fill');
    const [timerSec, setTimerSec] = useState(0);
    const [timerOn, setTimerOn] = useState(false);
    const [undoStack, setUndoStack] = useState<{ r: number, c: number, prev: number }[][]>([]);

    const [clueDoneRows, setClueDoneRows] = useState<boolean[]>(Array(rows).fill(false));
    const [clueDoneCols, setClueDoneCols] = useState<boolean[]>(Array(cols).fill(false));

    // Hints
    const [hintsLeft, setHintsLeft] = useState(3);
    const [hintCell, setHintCell] = useState<{ type: 'row' | 'col', index: number } | null>(null);

    // Status
    const [toastMsg, setToastMsg] = useState('');
    const [progress, setProgress] = useState(0);

    // Win / Reveal State
    const [isRevealed, setIsRevealed] = useState(false);
    const [showWinSheet, setShowWinSheet] = useState(false);

    const actxRef = useRef<AudioContext | null>(null);
    const hasRevealed = useRef(false);

    useEffect(() => {
        // Load save
        if (id) {
            try {
                const saved = localStorage.getItem(`nono_${id}`);
                if (saved) {
                    if (window.confirm('Welcome back! Would you like to resume your saved progress?')) {
                        const parsed = JSON.parse(saved);
                        if (parsed && parsed.length === rows && parsed[0].length === cols) {
                            setPlayerGrid(parsed);
                            setTimerOn(true); // resume instantly
                        }
                    } else {
                        safeRemove(`nono_${id}`);
                    }
                }
            } catch (e) {
                console.error(e);
            }
        }

        // Setup Audio Context interaction listener
        const initAudio = () => {
            if (!actxRef.current) {
                const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
                actxRef.current = new AudioContext();
            }
        };
        document.addEventListener('pointerdown', initAudio, { once: true });
        document.addEventListener('keydown', initAudio, { once: true });

        // Warn before leaving mid-puzzle
        const onPopState = () => {
            if (timerOn && !window.confirm('Leave this puzzle? Your progress will be lost.')) {
                window.history.pushState(null, '', location.href);
            } else {
                onBack();
            }
        };
        window.history.pushState(null, '', location.href);
        window.addEventListener('popstate', onPopState);

        return () => {
            document.removeEventListener('pointerdown', initAudio);
            document.removeEventListener('keydown', initAudio);
            window.removeEventListener('popstate', onPopState);
        };
    }, []);

    // Timer Interval
    useEffect(() => {
        if (!timerOn) return;
        const interval = setInterval(() => {
            setTimerSec(s => s + 1);
        }, 1000);
        return () => clearInterval(interval);
    }, [timerOn]);

    // Validation Effect (runs whenever playerGrid changes)
    useEffect(() => {
        let win = true;
        let filledCount = 0;
        const newlyDoneRows = [...clueDoneRows];
        const newlyDoneCols = [...clueDoneCols];
        let playedSound = false;

        const bin = playerGrid.map(row => row.map(v => v === 1 ? 1 : 0));

        // Rows
        for (let r = 0; r < rows; r++) {
            const rmText = computeClues(bin[r]).join(',');
            const ansText = computeClues(answerGrid[r]).join(',');
            const isDone = rmText === ansText;
            if (isDone && !clueDoneRows[r]) playedSound = true;
            newlyDoneRows[r] = isDone;
        }

        // Cols
        for (let c = 0; c < cols; c++) {
            const colBin = bin.map(row => row[c]);
            const colAns = answerGrid.map(row => row[c]);
            const cmText = computeClues(colBin).join(',');
            const ansText = computeClues(colAns).join(',');
            const isDone = cmText === ansText;
            if (isDone && !clueDoneCols[c]) playedSound = true;
            newlyDoneCols[c] = isDone;
        }

        if (playedSound && actxRef.current) {
            const actx = actxRef.current;
            const osc = actx.createOscillator();
            const gain = actx.createGain();
            osc.type = 'sine'; osc.frequency.setValueAtTime(800, actx.currentTime);
            osc.frequency.exponentialRampToValueAtTime(1200, actx.currentTime + 0.05);
            gain.gain.setValueAtTime(0.1, actx.currentTime);
            gain.gain.exponentialRampToValueAtTime(0.001, actx.currentTime + 0.1);
            osc.connect(gain); gain.connect(actx.destination);
            osc.start(); osc.stop(actx.currentTime + 0.1);
        }

        for (let r = 0; r < rows; r++) {
            for (let c = 0; c < cols; c++) {
                const tv = answerGrid[r][c] === 1;
                const pv = playerGrid[r][c] === 1;
                if (playerGrid[r][c] === 1 || playerGrid[r][c] === 2 || playerGrid[r][c] === 3) filledCount++;
                if (tv !== pv) win = false;
            }
        }

        setClueDoneRows(newlyDoneRows);
        setClueDoneCols(newlyDoneCols);

        const prog = Math.min(100, Math.round((filledCount / (rows * cols)) * 100));
        setProgress(prog);

        if (id && timerOn) {
            safeSave(`nono_${id}`, JSON.stringify(playerGrid));
        }

        if (win && !hasRevealed.current) {
            hasRevealed.current = true;
            setTimerOn(false);
            if (id) safeRemove(`nono_${id}`);
            setTimeout(() => {
                setIsRevealed(true);
                setTimeout(() => setShowWinSheet(true), 1600);
            }, 200);
        }
    }, [playerGrid]);

    const handleApplyCell = useCallback((r: number, c: number, v: number) => {
        if (!timerOn && !isRevealed) setTimerOn(true);
        setPlayerGrid(prev => {
            const next = [...prev];
            next[r] = [...next[r]];
            next[r][c] = v;
            return next;
        });
    }, [timerOn, isRevealed]);

    const handleDragEnd = useCallback((group: { r: number, c: number, prev: number }[]) => {
        setUndoStack(prev => {
            const next = [...prev, group];
            if (next.length > 50) next.shift();
            return next;
        });
    }, []);

    const handleUndo = () => {
        if (undoStack.length === 0) return;
        const newStack = [...undoStack];
        const group = newStack.pop()!;

        setPlayerGrid(prev => {
            const next = [...prev];
            for (let i = group.length - 1; i >= 0; i--) {
                const step = group[i];
                next[step.r] = [...next[step.r]];
                next[step.r][step.c] = step.prev;
            }
            return next;
        });
        setUndoStack(newStack);
    };

    const handleHint = () => {
        if (hintsLeft <= 0) return;
        // find a cell
        let found = null;
        for (let r = 0; r < rows; r++) {
            if (found) break;
            const det = getDeterminableCells(cols, rowClues[r]);
            for (const c of det) {
                const tv = answerGrid[r][c] === 1 ? 1 : 2;
                if (tv === 1 && playerGrid[r][c] !== 1) { found = { type: 'row', index: r }; break; }
            }
        }
        for (let c = 0; c < cols; c++) {
            if (found) break;
            const det = getDeterminableCells(rows, colClues[c]);
            for (const r of det) {
                const tv = answerGrid[r][c] === 1 ? 1 : 2;
                if (tv === 1 && playerGrid[r][c] !== 1) { found = { type: 'col', index: c }; break; }
            }
        }

        if (found) {
            setHintsLeft(h => h - 1);
            setHintCell(found as { type: 'row' | 'col', index: number });
            setTimeout(() => setHintCell(null), 1500);
        } else {
            setToastMsg('No simple logical hints available right now!');
        }
    };

    const handleCheck = () => {
        let filled = 0;
        for (let r = 0; r < rows; r++) for (let c = 0; c < cols; c++) if (playerGrid[r][c] !== 0) filled++;

        if (filled / (rows * cols) < 0.3) {
            setToastMsg('Fill in more cells first!');
            return;
        }

        let bad = false;
        for (let r = 0; r < rows; r++) {
            for (let c = 0; c < cols; c++) {
                if (playerGrid[r][c] === 0) continue;
                if ((playerGrid[r][c] === 1 ? 1 : 0) !== answerGrid[r][c]) {
                    bad = true;
                    const el = document.querySelector(`.gcell[data-r="${r}"][data-c="${c}"]`);
                    if (el) { el.classList.add('wrong'); setTimeout(() => el.classList.remove('wrong'), 800); }
                } else {
                    const el = document.querySelector(`.gcell[data-r="${r}"][data-c="${c}"]`);
                    if (el) { el.classList.add('ok-flash'); setTimeout(() => el.classList.remove('ok-flash'), 800); }
                }
            }
        }
        if (!bad) setToastMsg('Looking good! ✓');
    };

    const handleGiveUp = () => {
        if (!window.confirm('Reveal the solution?')) return;
        setTimerOn(false);
        if (id) safeRemove(`nono_${id}`);

        // Show incorrect cells briefly
        for (let r = 0; r < rows; r++) {
            for (let c = 0; c < cols; c++) {
                const tv = answerGrid[r][c] === 1;
                const pv = playerGrid[r][c] === 1;
                const el = document.querySelector(`.gcell[data-r="${r}"][data-c="${c}"]`) as HTMLElement;
                if (!el) continue;
                if (tv && !pv) el.style.background = 'var(--success)';
                else if (!tv && pv) el.style.background = 'var(--danger)';
            }
        }

        setTimeout(() => {
            // force answer grid
            setPlayerGrid(answerGrid.map(row => row.map(v => v === 1 ? 1 : 0)));
            setIsRevealed(true);
            setTimeout(() => setShowWinSheet(true), 1600);
        }, 3000);
    };

    const formatTime = (secs: number) => {
        const h = Math.floor(secs / 3600);
        const m = String(Math.floor((secs % 3600) / 60)).padStart(2, '0');
        const s = String(secs % 60).padStart(2, '0');
        return h > 0 ? `${h}:${m}:${s}` : `${m}:${s}`;
    };

    return (
        <div className="flex flex-col h-full bg-[#faf7f2] fixed inset-0 z-[100]">
            {/* Topbar */}
            <div className="flex items-center gap-3 p-[10px_20px] bg-white border-b border-solid border-bdr flex-wrap relative z-20">
                <button onClick={onBack} className="bg-transparent border-none text-muted font-mono text-[14px] cursor-pointer py-2 inline-flex items-center hover:text-terra order-1 md:order-none mr-auto">
                    ← Back
                </button>
                <div id="timer" className="font-mono text-[15px] font-bold text-text whitespace-nowrap order-2 md:order-none md:ml-auto">
                    {formatTime(timerSec)}
                </div>

                <div className="hidden md:flex ml-auto order-3">
                    <Toolbar activeTool={activeTool} onToolChange={setActiveTool} onUndo={handleUndo} canUndo={undoStack.length > 0} />
                </div>

                <div className="flex items-center gap-2 order-4">
                    <button
                        onClick={handleHint}
                        disabled={hintsLeft === 0}
                        className="font-mono text-[12px] bg-white border border-solid border-bdr text-body px-3 py-1.5 rounded-full cursor-pointer hover:border-terra disabled:opacity-50"
                    >
                        💡 {hintsLeft}
                    </button>
                    <button
                        onClick={handleCheck}
                        className="font-mono text-[11px] bg-white border border-solid border-bdr text-muted px-3 py-1.5 rounded-full cursor-pointer hover:border-terra hover:text-terra"
                    >
                        ✓ Check
                    </button>
                    <button
                        onClick={handleGiveUp}
                        className="font-mono text-[14px] bg-transparent border-none text-muted w-8 h-8 rounded-[8px] flex items-center justify-center hover:bg-bg cursor-pointer"
                    >
                        ⋮
                    </button>
                </div>
            </div>

            {/* Progress Bar */}
            <div className="w-full max-w-[480px] mx-auto px-5 mt-3 mb-1 flex items-center gap-3 shrink-0">
                <div className="flex-1 h-[6px] bg-[#e0e0e0] rounded-[3px] overflow-hidden">
                    <div className="h-full bg-success transition-[width_0.3s]" style={{ width: `${progress}%` }} />
                </div>
                <div className="font-mono text-[11px] text-muted min-w-[36px] text-right">
                    {progress}%
                </div>
            </div>

            {/* Main Game Grid Component */}
            <PuzzleGrid
                puzzleData={puzzleData}
                playerGrid={playerGrid}
                activeTool={activeTool}
                onApplyCell={handleApplyCell}
                onDragEnd={handleDragEnd}
                clueDoneRows={clueDoneRows}
                clueDoneCols={clueDoneCols}
                isRevealed={isRevealed}
                hintCell={hintCell}
            />

            {/* Mobile Toolbar Overlay */}
            <div className="md:hidden">
                <Toolbar activeTool={activeTool} onToolChange={setActiveTool} onUndo={handleUndo} canUndo={undoStack.length > 0} />
            </div>

            {toastMsg && (
                <Toast message={toastMsg} onComplete={() => setToastMsg('')} />
            )}

            {showWinSheet && (
                <RevealAnimation
                    puzzleData={puzzleData}
                    timeStr={formatTime(timerSec)}
                    onClose={onBack}
                    onShareResult={() => {
                        const text = `I solved the Revelio puzzle "${puzzleData.title}" in ${formatTime(timerSec)}!\n${location.href}`;
                        if (navigator.share) navigator.share({ text, url: location.href });
                        else {
                            navigator.clipboard.writeText(text);
                            setToastMsg('Result copied!');
                        }
                    }}
                    onSaveImage={() => {
                        // Drawing social card logic via canvas
                        const cv = document.createElement('canvas');
                        cv.width = 1080; cv.height = 1920;
                        const ctx = cv.getContext('2d');
                        if (!ctx) return;
                        ctx.fillStyle = '#faf7f2'; ctx.fillRect(0, 0, 1080, 1920);

                        ctx.fillStyle = '#f4845f'; ctx.font = 'italic 700 80px Georgia, serif'; ctx.textAlign = 'center'; ctx.fillText('Revelio', 540, 250);
                        ctx.fillStyle = '#2d2d2d'; ctx.font = '600 50px -apple-system, sans-serif'; ctx.fillText(`I solved "${puzzleData.title}"!`, 540, 400);
                        ctx.font = '400 40px -apple-system, sans-serif'; ctx.fillStyle = '#6b6661'; ctx.fillText(`Time: ${formatTime(timerSec)}  •  Size: ${cols}x${rows}`, 540, 480);

                        if (puzzleData.thumb) {
                            const img = new window.Image();
                            img.onload = () => {
                                const imgSize = 700;
                                let dw = img.width, dh = img.height;
                                const ratio = dw / dh;
                                if (ratio > 1) { dw = imgSize; dh = imgSize / ratio; } else { dh = imgSize; dw = imgSize * ratio; }
                                ctx.save(); ctx.translate(540 - dw / 2, 960 - dh / 2);
                                ctx.shadowColor = 'rgba(0,0,0,0.15)'; ctx.shadowBlur = 40; ctx.shadowOffsetY = 20;
                                ctx.drawImage(img, 0, 0, dw, dh); ctx.restore();
                                ctx.fillStyle = '#b0a89e'; ctx.font = '30px -apple-system, sans-serif'; ctx.fillText('Make your own: revelio.link', 540, 1800);
                                const link = document.createElement('a'); link.download = `revelio_result_${puzzleData.id || 'puzzle'}.png`; link.href = cv.toDataURL('image/png'); link.click();
                            };
                            img.src = puzzleData.thumb;
                        }
                    }}
                />
            )}
        </div>
    );
}

function getDeterminableCells(L: number, runs: number[]): number[] {
    if (runs.length === 0) { const res = []; for (let i = 0; i < L; i++) res.push(i); return res; }
    const sum = runs.reduce((a, b) => a + b, 0); const slack = L - sum - (runs.length - 1);
    const res = []; let curr = 0; if (slack < 0) return [];
    if (slack === 0) { const res = []; for (let i = 0; i < L; i++) res.push(i); return res; }
    for (const c of runs) {
        if (c > slack) { const start = curr + slack; const end = curr + c; for (let i = start; i < end; i++) res.push(i); }
        curr += c + 1;
    }
    return res;
}

