import React, { useState, useEffect, useRef } from 'react';
import { Button } from './ui/Button';
import QRCode from 'qrcode';
import { PuzzleData, encodePuzzle } from '@/lib/puzzleEncoder';
import { DIFF_TAGS } from '@/lib/utils';

interface ShareScreenProps {
    puzzleData: PuzzleData;
    shareUrl: string;
    teaserThumb: string;
    onRegenerate: () => void;
    onPlay: () => void;
}

export default function ShareScreen({ puzzleData: initialData, shareUrl: initialUrl, teaserThumb, onRegenerate, onPlay }: ShareScreenProps) {
    const [puzzleData, setPuzzleData] = useState<PuzzleData>(initialData);
    const [url, setUrl] = useState<string>(initialUrl);
    const [caption, setCaption] = useState<string>(initialData.title);
    const [password, setPassword] = useState<string>(initialData.pw || '');
    const [showQR, setShowQR] = useState<boolean>(false);
    const [copyLinkText, setCopyLinkText] = useState('🔗 Copy Link');
    const [copyMsgText, setCopyMsgText] = useState('Copy Message');
    const [isMobile, setIsMobile] = useState(false);
    const [mounted, setMounted] = useState(false);
    const qrCanvasRef = useRef<HTMLCanvasElement>(null);

    useEffect(() => {
        setMounted(true);
        setIsMobile(/mobile|android|iphone|ipad/i.test(navigator.userAgent));
    }, []);

    const isUrlTooLong = url.length > 50000;
    const isUrlLong = url.length > 8000;

    useEffect(() => {
        // Re-generate URL when caption or password changes
        const newData = { ...puzzleData, title: caption || 'Can you guess what this is? 👀', pw: password || null };
        setPuzzleData(newData);
        const encoded = encodePuzzle(newData);
        const newUrl = `${window.location.origin}${window.location.pathname}?puzzle=${encoded}`;
        setUrl(newUrl);
    }, [caption, password]);

    useEffect(() => {
        if (!isUrlTooLong && showQR && qrCanvasRef.current) {
            QRCode.toCanvas(qrCanvasRef.current, url, { width: 200, color: { dark: '#2d2d2d', light: '#ffffff' } }, (err) => {
                if (err) console.error(err);
            });
        }
    }, [url, showQR, isUrlTooLong]);

    const handleCopyLink = () => {
        navigator.clipboard.writeText(url).then(() => {
            setCopyLinkText('Copied!');
            setTimeout(() => setCopyLinkText('🔗 Copy Link'), 2000);
        });
    };

    const handleShareChallenge = async () => {
        const text = `I made you a puzzle 🧩 Can you solve it without giving up?`;
        const shareURL = url;

        if (isMobile && navigator.share) {
            try {
                await navigator.share({ title: puzzleData.title || 'Solve my puzzle!', text, url: shareURL });
            } catch (err) {
                if ((err as Error).name !== 'AbortError') fallbackCopy(`${text}\n${shareURL}`);
            }
        } else {
            fallbackCopy(`${text}\n${shareURL}`);
        }
    };

    const fallbackCopy = async (content: string) => {
        await navigator.clipboard.writeText(content);
        setCopyMsgText('Copied!');
        setTimeout(() => setCopyMsgText('Copy Message'), 2000);
    };

    return (
        <div className="flex flex-col items-center p-[20px_20px_calc(40px+env(safe-area-inset-bottom,0px))] gap-4 max-w-[720px] w-full mx-auto">
            <h1 className="font-serif italic font-semibold text-[clamp(22px,5vw,32px)] text-text text-center">
                Puzzle Ready!
            </h1>
            <p className="text-[15px] text-body text-center max-w-[360px]">
                Copy the link below and send it to a friend. They don't need an app to play it.
            </p>

            <div className="bg-white rounded-[20px] shadow-[0_4px_32px_rgba(0,0,0,.1)] overflow-hidden w-full max-w-[440px]">
                {/* Teaser Image (Blurred via CSS or already blurred via canvas data URL) */}
                <img
                    src={teaserThumb}
                    className="block w-full h-[200px] object-cover [image-rendering:pixelated] blur-[3px] brightness-105"
                    alt="Hidden Puzzle"
                />

                <div className="p-[16px_18px_18px] flex flex-col gap-3">
                    <input
                        type="text"
                        value={caption}
                        onChange={e => setCaption(e.target.value)}
                        placeholder="Can you guess what this is? 👀"
                        className="font-caveat text-[20px] text-text border-none outline-none border-b-[1.5px] border-solid border-bdr pb-1.5 w-full bg-transparent min-h-[44px] focus:border-terra"
                    />

                    <div className="flex gap-2 flex-wrap">
                        <span className="font-mono text-[11px] text-muted bg-bg rounded-[20px] px-2.5 py-1 border border-solid border-bdr">
                            {puzzleData.cols} × {puzzleData.rows}
                        </span>
                        <span className="font-mono text-[11px] text-muted bg-bg rounded-[20px] px-2.5 py-1 border border-solid border-bdr">
                            {DIFF_TAGS[Math.min(puzzleData.diffIdx, 4)]}
                        </span>
                        <span className="font-mono text-[11px] text-muted bg-bg rounded-[20px] px-2.5 py-1 border border-solid border-bdr">
                            Logic: {puzzleData.logicDiff}
                        </span>
                    </div>

                    <h3 className="font-mono text-[12px] text-muted mt-2 font-semibold">Optional Security</h3>
                    <input
                        type="text"
                        value={password}
                        onChange={e => setPassword(e.target.value)}
                        placeholder="Add password to lock puzzle..."
                        className="font-sans text-[14px] text-text border border-solid border-bdr p-[8px_12px] rounded-DEFAULT w-full bg-transparent min-h-[44px] focus:border-terra outline-none transition-colors"
                    />
                </div>
            </div>

            <div className="flex flex-col gap-2.5 w-full max-w-[440px]">
                <Button variant="terra" size="full" onClick={handleCopyLink}>
                    {copyLinkText}
                </Button>
                <div className="flex gap-2.5 w-full">
                    <Button variant="outline" className="flex-1" onClick={handleShareChallenge}>
                        {mounted && isMobile && !!navigator.share ? 'Send to Friend →' : copyMsgText}
                    </Button>
                    <Button variant="ghost" className="flex-1" onClick={onPlay}>
                        Play It Myself
                    </Button>
                </div>
            </div>

            <button
                onClick={() => setShowQR(!showQR)}
                className="font-mono text-[12px] text-muted bg-transparent border-none cursor-pointer py-1 min-h-[44px] transition-colors hover:text-terra"
            >
                {showQR ? 'Hide QR ▴' : 'Show QR Code ▾'}
            </button>

            {mounted && showQR && (
                <div id="qrWrap" className="flex flex-col items-center gap-2.5 bg-white rounded-DEFAULT shadow p-5 w-full max-w-[440px]">
                    {isUrlTooLong ? (
                        <div className="text-center text-body text-[13px]">QR code cannot be generated (URL too long)</div>
                    ) : (
                        <>
                            <div className="text-[12px] text-muted text-center">Long-press to save</div>
                            <canvas ref={qrCanvasRef} className="rounded-[8px]" />
                        </>
                    )}
                </div>
            )}

            {isUrlTooLong ? (
                <div className="text-[12px] text-body text-center max-w-[440px] bg-[#fffbf0] border border-solid border-[#f9e090] rounded-DEFAULT p-[10px_14px] leading-relaxed">
                    ⚠️ This puzzle is very large — the QR code may not scan reliably. The copy-link still works perfectly.
                </div>
            ) : isUrlLong ? (
                <div className="text-[12px] text-body text-center max-w-[440px] bg-[#fffbf0] border border-solid border-[#f9e090] rounded-DEFAULT p-[10px_14px] leading-relaxed">
                    Your puzzle is large — the QR code may be hard to scan. The link works fine.
                </div>
            ) : null}

            <div className="flex flex-col gap-2 w-full max-w-[440px] items-center mt-4">
                <button onClick={onRegenerate} className="btn-sm font-mono text-muted bg-transparent border-none cursor-pointer flex items-center justify-center gap-1 hover:text-terra h-[36px]">
                    ↺ Re-generate Puzzle
                </button>
            </div>

        </div>
    );
}

/**
 * imageToNonogram.ts
 * ==================
 * Complete, smart image → nonogram puzzle conversion pipeline.
 * Drop this file into your Next.js /lib/ folder.
 *
 * Pipeline:
 *  1. Load image onto canvas → raw RGBA pixels
 *  2. Correct EXIF orientation (iPhone photos)
 *  3. Composite transparent PNGs onto white
 *  4. Convert to perceptual greyscale (luminance formula)
 *  5. Smart downsampling to target grid size (area averaging)
 *  6. Otsu's method for optimal threshold
 *  7. Fill ratio check + adaptive nudge
 *  8. Generate nonogram clues
 *  9. Solvability scoring
 * 10. Difficulty rating
 * 11. Smart grid size suggestions based on image aspect ratio
 */

// ─────────────────────────────────────────────
// TYPES
// ─────────────────────────────────────────────

export interface GridOption {
    label: 'Sketch' | 'Simple' | 'Balanced' | 'Crisp' | 'Ultra'
    cols: number
    rows: number
    difficulty: 'Easy' | 'Medium' | 'Hard' | 'Expert'
    fillRatio?: number       // populated after preview generation
    isBestPick?: boolean
    warning?: string
}

export interface NonogramPuzzle {
    grid: number[][]         // 1 = filled, 0 = empty  [row][col]
    rowClues: number[][]
    colClues: number[][]
    rows: number
    cols: number
    difficulty: 'Easy' | 'Medium' | 'Hard' | 'Expert'
    difficultyScore: number  // 0–100
    solvabilityScore: number // 0–100, how many cells are immediately deterministic
    fillRatio: number        // 0–1
    threshold: number        // the Otsu threshold used
    warnings: string[]
}

export interface ProcessedImage {
    greyscale: number[][]    // [row][col], 0–255
    width: number
    height: number
    aspectRatio: number
}

// ─────────────────────────────────────────────
// STEP 1 — LOAD IMAGE FROM FILE
// ─────────────────────────────────────────────

export async function loadImageFromFile(file: File): Promise<HTMLImageElement> {
    return new Promise((resolve, reject) => {
        const url = URL.createObjectURL(file)
        const img = new Image()
        img.onload = () => {
            URL.revokeObjectURL(url)
            resolve(img)
        }
        img.onerror = () => reject(new Error('Failed to load image'))
        img.src = url
    })
}

// ─────────────────────────────────────────────
// STEP 2 — EXIF ORIENTATION CORRECTION
// iPhone photos are often rotated in metadata.
// We read the EXIF orientation tag and rotate the
// canvas accordingly before processing.
// ─────────────────────────────────────────────

async function getExifOrientation(file: File): Promise<number> {
    return new Promise((resolve) => {
        const reader = new FileReader()
        reader.onload = (e) => {
            const view = new DataView(e.target?.result as ArrayBuffer)
            if (view.getUint16(0, false) !== 0xFFD8) return resolve(1)
            let offset = 2
            while (offset < view.byteLength) {
                const marker = view.getUint16(offset, false)
                offset += 2
                if (marker === 0xFFE1) {
                    if (view.getUint32(offset += 2, false) !== 0x45786966) return resolve(1)
                    const little = view.getUint16(offset += 6, false) === 0x4949
                    offset += view.getUint32(offset + 4, little)
                    const tags = view.getUint16(offset, little)
                    offset += 2
                    for (let i = 0; i < tags; i++) {
                        if (view.getUint16(offset + i * 12, little) === 0x0112) {
                            return resolve(view.getUint16(offset + i * 12 + 8, little))
                        }
                    }
                } else if ((marker & 0xFF00) !== 0xFF00) break
                else offset += view.getUint16(offset, false)
            }
            resolve(1)
        }
        reader.readAsArrayBuffer(file.slice(0, 64 * 1024))
    })
}

function drawImageWithOrientation(
    ctx: CanvasRenderingContext2D,
    img: HTMLImageElement,
    orientation: number,
    width: number,
    height: number
): void {
    ctx.save()
    switch (orientation) {
        case 2: ctx.transform(-1, 0, 0, 1, width, 0); break
        case 3: ctx.transform(-1, 0, 0, -1, width, height); break
        case 4: ctx.transform(1, 0, 0, -1, 0, height); break
        case 5: ctx.transform(0, 1, 1, 0, 0, 0); break
        case 6: ctx.transform(0, 1, -1, 0, height, 0); break
        case 7: ctx.transform(0, -1, -1, 0, height, width); break
        case 8: ctx.transform(0, -1, 1, 0, 0, width); break
    }
    ctx.drawImage(img, 0, 0)
    ctx.restore()
}

// ─────────────────────────────────────────────
// STEP 3+4 — RGBA → PERCEPTUAL GREYSCALE
// Uses the ITU-R BT.709 luminance formula.
// Simple RGB average gives wrong results (green
// looks too dark, blue too light to human eye).
// ─────────────────────────────────────────────

function rgbaToGreyscale(r: number, g: number, b: number, a: number): number {
    // Composite onto white background first (handles transparent PNGs)
    const alpha = a / 255
    const rr = Math.round(r * alpha + 255 * (1 - alpha))
    const gg = Math.round(g * alpha + 255 * (1 - alpha))
    const bb = Math.round(b * alpha + 255 * (1 - alpha))
    // Perceptual luminance — NOT simple average
    return 0.2126 * rr + 0.7152 * gg + 0.0722 * bb
}

// ─────────────────────────────────────────────
// STEP 5 — SMART DOWNSAMPLING (Area Averaging)
// For each target cell, average ALL source pixels
// that fall within that cell's area. Much better
// than nearest-neighbour which causes aliasing.
// ─────────────────────────────────────────────

function downsampleGreyscale(
    pixels: Uint8ClampedArray,
    srcW: number,
    srcH: number,
    targetCols: number,
    targetRows: number
): number[][] {
    const result: number[][] = []

    for (let row = 0; row < targetRows; row++) {
        result[row] = []
        const y0 = (row / targetRows) * srcH
        const y1 = ((row + 1) / targetRows) * srcH

        for (let col = 0; col < targetCols; col++) {
            const x0 = (col / targetCols) * srcW
            const x1 = ((col + 1) / targetCols) * srcW

            let sum = 0
            let count = 0

            // Integer pixel loop over the source area
            for (let py = Math.floor(y0); py < Math.ceil(y1); py++) {
                for (let px = Math.floor(x0); px < Math.ceil(x1); px++) {
                    // Weight by how much of this source pixel falls in the area
                    const xWeight = Math.min(px + 1, x1) - Math.max(px, x0)
                    const yWeight = Math.min(py + 1, y1) - Math.max(py, y0)
                    const weight = xWeight * yWeight

                    const idx = (py * srcW + px) * 4
                    const grey = rgbaToGreyscale(
                        pixels[idx], pixels[idx + 1], pixels[idx + 2], pixels[idx + 3]
                    )
                    sum += grey * weight
                    count += weight
                }
            }

            result[row][col] = count > 0 ? sum / count : 255
        }
    }

    return result
}

// ─────────────────────────────────────────────
// STEP 6 — OTSU'S METHOD (Optimal Threshold)
// Finds the threshold T that maximizes the
// between-class variance of dark vs light pixels.
// Works far better than a fixed 128 threshold,
// especially for night photos and overexposed shots.
// ─────────────────────────────────────────────

function otsuThreshold(greyscale: number[][]): number {
    const histogram = new Array(256).fill(0)
    const rows = greyscale.length
    const cols = greyscale[0].length
    const total = rows * cols

    for (let r = 0; r < rows; r++) {
        for (let c = 0; c < cols; c++) {
            histogram[Math.round(greyscale[r][c])]++
        }
    }

    let sum = 0
    for (let i = 0; i < 256; i++) sum += i * histogram[i]

    let sumB = 0
    let wB = 0
    let maxVariance = 0
    let threshold = 128

    for (let t = 0; t < 256; t++) {
        wB += histogram[t]
        if (wB === 0) continue
        const wF = total - wB
        if (wF === 0) break

        sumB += t * histogram[t]
        const mB = sumB / wB
        const mF = (sum - sumB) / wF
        const variance = wB * wF * (mB - mF) * (mB - mF)

        if (variance > maxVariance) {
            maxVariance = variance
            threshold = t
        }
    }

    return threshold
}

// ─────────────────────────────────────────────
// STEP 7 — APPLY THRESHOLD + FILL RATIO CHECK
// After thresholding, check the fill ratio.
// If outside the 20–80% sweet spot, nudge the
// threshold iteratively until it's acceptable.
// ─────────────────────────────────────────────

function applyThreshold(greyscale: number[][], threshold: number): number[][] {
    return greyscale.map(row =>
        row.map(val => val <= threshold ? 1 : 0)
    )
}

function calculateFillRatio(grid: number[][]): number {
    let filled = 0
    let total = 0
    for (const row of grid) {
        for (const cell of row) {
            if (cell === 1) filled++
            total++
        }
    }
    return filled / total
}

function applyThresholdWithFallback(
    greyscale: number[][],
    baseThreshold: number
): { grid: number[][], threshold: number, fillRatio: number } {
    let threshold = baseThreshold
    let grid = applyThreshold(greyscale, threshold)
    let fillRatio = calculateFillRatio(grid)

    // If fill ratio is outside 15–85%, nudge toward 50%
    // Try up to 20 iterations of nudging
    let attempts = 0
    while ((fillRatio < 0.15 || fillRatio > 0.85) && attempts < 20) {
        if (fillRatio < 0.15) threshold = Math.min(255, threshold + 10)
        if (fillRatio > 0.85) threshold = Math.max(0, threshold - 10)
        grid = applyThreshold(greyscale, threshold)
        fillRatio = calculateFillRatio(grid)
        attempts++
    }

    return { grid, threshold, fillRatio }
}

// ─────────────────────────────────────────────
// STEP 8 — CLUE GENERATION
// A clue is the list of consecutive run lengths
// for filled cells in each row and column.
// e.g. [1,1,0,1,1,1] → [2, 3]
// Empty row → [0]  (important: never blank)
// ─────────────────────────────────────────────

function generateClues(sequence: number[]): number[] {
    const clues: number[] = []
    let run = 0

    for (const cell of sequence) {
        if (cell === 1) {
            run++
        } else if (run > 0) {
            clues.push(run)
            run = 0
        }
    }
    if (run > 0) clues.push(run)
    return clues.length > 0 ? clues : [0]
}

function generateAllClues(grid: number[][]): {
    rowClues: number[][]
    colClues: number[][]
} {
    const rows = grid.length
    const cols = grid[0].length

    const rowClues = grid.map(row => generateClues(row))

    const colClues: number[][] = []
    for (let c = 0; c < cols; c++) {
        const col = grid.map(row => row[c])
        colClues.push(generateClues(col))
    }

    return { rowClues, colClues }
}

// ─────────────────────────────────────────────
// STEP 9 — SOLVABILITY SCORING
// Counts what percentage of cells can be
// determined by logic on the first pass.
// Uses two core nonogram logic rules:
//   Rule A: if clue sum + gaps >= line length → overlap cells are forced filled
//   Rule B: if clue is [0] → entire line is forced empty
// Higher score = more immediately solvable = better puzzle
// ─────────────────────────────────────────────

function countDeterministicCells(clues: number[][], lineLength: number): number {
    let deterministic = 0

    for (const clue of clues) {
        // Rule B: empty line
        if (clue.length === 1 && clue[0] === 0) {
            deterministic += lineLength
            continue
        }

        // Rule A: overlap method
        // Minimum space needed = sum of clues + (gaps between them)
        const minSpace = clue.reduce((a, b) => a + b, 0) + (clue.length - 1)
        const slack = lineLength - minSpace

        // Each run of length L with slack S contributes max(0, L - S) forced cells
        for (const run of clue) {
            const forced = Math.max(0, run - slack)
            deterministic += forced
        }
    }

    return deterministic
}

function scoreSolvability(
    rowClues: number[][],
    colClues: number[][],
    rows: number,
    cols: number
): number {
    const totalCells = rows * cols
    const rowDet = countDeterministicCells(rowClues, cols)
    const colDet = countDeterministicCells(colClues, rows)
    // Combine row and col deterministic cells, cap at totalCells
    const totalDet = Math.min(totalCells, rowDet + colDet)
    return Math.round((totalDet / totalCells) * 100)
}

// ─────────────────────────────────────────────
// STEP 10 — DIFFICULTY RATING
// Combines fill ratio, clue complexity, and
// solvability score into a human-readable label.
// ─────────────────────────────────────────────

function rateDifficulty(
    rows: number,
    cols: number,
    fillRatio: number,
    solvabilityScore: number,
    rowClues: number[][],
    colClues: number[][]
): { difficulty: 'Easy' | 'Medium' | 'Hard' | 'Expert', score: number } {
    // Average number of clue groups per line (more groups = harder)
    const avgRowGroups = rowClues.reduce((s, c) => s + (c[0] === 0 ? 0 : c.length), 0) / rows
    const avgColGroups = colClues.reduce((s, c) => s + (c[0] === 0 ? 0 : c.length), 0) / cols
    const avgGroups = (avgRowGroups + avgColGroups) / 2

    // Score from 0–100 (higher = harder)
    const sizeScore = Math.min(100, (rows * cols) / 6)         // bigger grid = harder
    const groupScore = Math.min(100, avgGroups * 20)            // more clue groups = harder
    const solvScore = 100 - solvabilityScore                    // less deterministic = harder
    const balanceScore = Math.abs(fillRatio - 0.5) * 100       // extreme fill = harder

    const totalScore = Math.round(
        sizeScore * 0.25 +
        groupScore * 0.30 +
        solvScore * 0.35 +
        balanceScore * 0.10
    )

    let difficulty: 'Easy' | 'Medium' | 'Hard' | 'Expert'
    if (totalScore < 25) difficulty = 'Easy'
    else if (totalScore < 50) difficulty = 'Medium'
    else if (totalScore < 75) difficulty = 'Hard'
    else difficulty = 'Expert'

    return { difficulty, score: totalScore }
}

// ─────────────────────────────────────────────
// STEP 11 — SMART GRID SIZE SUGGESTIONS
// Given an image's aspect ratio, returns 3–5
// grid options that preserve the ratio and make
// sense for this specific image.
// ─────────────────────────────────────────────

const GRID_LABELS: GridOption['label'][] = ['Sketch', 'Simple', 'Balanced', 'Crisp', 'Ultra']
const DIFFICULTY_MAP: GridOption['difficulty'][] = ['Easy', 'Easy', 'Medium', 'Hard', 'Expert']
// Target cell counts for each difficulty tier
const TARGET_LONG_SIDES = [6, 10, 15, 20, 25]

export function suggestGridSizes(imageWidth: number, imageHeight: number): GridOption[] {
    const isLandscape = imageWidth >= imageHeight
    const longSide = Math.max(imageWidth, imageHeight)
    const shortSide = Math.min(imageWidth, imageHeight)
    const ratio = shortSide / longSide  // always ≤ 1

    const options: GridOption[] = []
    const warnings: string[] = []

    // Warn about extreme aspect ratios
    if (ratio < 0.3) {
        warnings.push('This image is very wide or very tall — consider cropping for a better puzzle')
    }

    for (let i = 0; i < TARGET_LONG_SIDES.length; i++) {
        const targetLong = TARGET_LONG_SIDES[i]
        const targetShort = Math.max(4, Math.round(targetLong * ratio))

        // Snap to at least 4 on the short side
        const finalLong = Math.min(30, targetLong)
        const finalShort = Math.max(4, targetShort)

        const cols = isLandscape ? finalLong : finalShort
        const rows = isLandscape ? finalShort : finalLong

        options.push({
            label: GRID_LABELS[i],
            cols,
            rows,
            difficulty: DIFFICULTY_MAP[i],
            isBestPick: false,
            warning: warnings[0],
        })
    }

    // Mark best pick: find the option closest to 40% fill
    // (we don't know fill yet, so pick 'Balanced' by default — index 2)
    // This gets updated after preview generation with real fill ratios
    options[2].isBestPick = true

    return options
}

// After generating previews, update best pick based on actual fill ratio
export function updateBestPick(options: GridOption[]): GridOption[] {
    let bestIdx = 0
    let bestScore = Infinity

    for (let i = 0; i < options.length; i++) {
        const ratio = options[i].fillRatio ?? 0.5
        // Ideal fill ratio is 40% — closest to that wins
        const score = Math.abs(ratio - 0.40)
        if (score < bestScore) {
            bestScore = score
            bestIdx = i
        }
    }

    return options.map((opt, i) => ({ ...opt, isBestPick: i === bestIdx }))
}

// ─────────────────────────────────────────────
// MAIN EXPORT — processImage()
// Call this with a File and a GridOption.
// Returns a complete NonogramPuzzle ready to play.
// ─────────────────────────────────────────────

export async function processImage(
    file: File,
    gridOption: GridOption
): Promise<NonogramPuzzle> {
    const { cols: targetCols, rows: targetRows } = gridOption
    const warnings: string[] = []

    // Load image
    const img = await loadImageFromFile(file)

    // Get EXIF orientation and correct it
    const orientation = await getExifOrientation(file)
    const swapDims = orientation >= 5 && orientation <= 8
    const canvasW = swapDims ? img.height : img.width
    const canvasH = swapDims ? img.width : img.height

    // Draw onto canvas (with orientation correction + white background)
    const canvas = document.createElement('canvas')
    canvas.width = canvasW
    canvas.height = canvasH
    const ctx = canvas.getContext('2d')!

    // White background (handles transparent PNGs)
    ctx.fillStyle = '#ffffff'
    ctx.fillRect(0, 0, canvasW, canvasH)
    drawImageWithOrientation(ctx, img, orientation, canvasW, canvasH)

    // Get raw pixels
    const imageData = ctx.getImageData(0, 0, canvasW, canvasH)
    const pixels = imageData.data

    // Downsample to target grid size using area averaging
    const greyscale = downsampleGreyscale(pixels, canvasW, canvasH, targetCols, targetRows)

    // Otsu threshold
    const otsuT = otsuThreshold(greyscale)

    // Apply threshold with fill ratio safety check
    const { grid, threshold, fillRatio } = applyThresholdWithFallback(greyscale, otsuT)

    // Warnings
    if (fillRatio < 0.15) {
        warnings.push('Very few filled cells — try a darker photo or larger grid')
    }
    if (fillRatio > 0.85) {
        warnings.push('Almost entirely filled — try a lighter photo or smaller grid')
    }
    if (fillRatio < 0.10 || fillRatio > 0.90) {
        warnings.push('This photo may not make a good puzzle at this size')
    }

    // Generate clues
    const { rowClues, colClues } = generateAllClues(grid)

    // Solvability score
    const solvabilityScore = scoreSolvability(rowClues, colClues, targetRows, targetCols)

    if (solvabilityScore < 20) {
        warnings.push('This puzzle may require a lot of guessing — try a different grid size')
    }

    // Difficulty rating
    const { difficulty, score: difficultyScore } = rateDifficulty(
        targetRows, targetCols, fillRatio, solvabilityScore, rowClues, colClues
    )

    return {
        grid,
        rowClues,
        colClues,
        rows: targetRows,
        cols: targetCols,
        difficulty,
        difficultyScore,
        solvabilityScore,
        fillRatio,
        threshold,
        warnings,
    }
}

// ─────────────────────────────────────────────
// PREVIEW HELPER — generatePreview()
// Fast version for the grid picker previews.
// Returns a grid WITHOUT full puzzle analysis.
// Call this for each grid option on the picker screen.
// ─────────────────────────────────────────────

export async function generatePreview(
    file: File,
    cols: number,
    rows: number
): Promise<{ grid: number[][], fillRatio: number }> {
    const img = await loadImageFromFile(file)
    const orientation = await getExifOrientation(file)
    const swapDims = orientation >= 5 && orientation <= 8
    const canvasW = swapDims ? img.height : img.width
    const canvasH = swapDims ? img.width : img.height

    const canvas = document.createElement('canvas')
    canvas.width = canvasW
    canvas.height = canvasH
    const ctx = canvas.getContext('2d')!
    ctx.fillStyle = '#ffffff'
    ctx.fillRect(0, 0, canvasW, canvasH)
    drawImageWithOrientation(ctx, img, orientation, canvasW, canvasH)

    const pixels = ctx.getImageData(0, 0, canvasW, canvasH).data
    const greyscale = downsampleGreyscale(pixels, canvasW, canvasH, cols, rows)
    const threshold = otsuThreshold(greyscale)
    const { grid, fillRatio } = applyThresholdWithFallback(greyscale, threshold)

    return { grid, fillRatio }
}

// ─────────────────────────────────────────────
// RESIZE HELPER — resizeForStorage()
// Resizes the original image to max 400px longest
// side for storage in URL / KV / Blob.
// Returns a base64 JPEG string.
// ─────────────────────────────────────────────

export async function resizeForStorage(file: File, maxSize = 400): Promise<string> {
    const img = await loadImageFromFile(file)
    const orientation = await getExifOrientation(file)
    const swapDims = orientation >= 5 && orientation <= 8
    const srcW = swapDims ? img.height : img.width
    const srcH = swapDims ? img.width : img.height

    const scale = Math.min(1, maxSize / Math.max(srcW, srcH))
    const w = Math.round(srcW * scale)
    const h = Math.round(srcH * scale)

    const canvas = document.createElement('canvas')
    canvas.width = w
    canvas.height = h
    const ctx = canvas.getContext('2d')!
    ctx.fillStyle = '#ffffff'
    ctx.fillRect(0, 0, w, h)
    drawImageWithOrientation(ctx, img, orientation, w, h)

    return canvas.toDataURL('image/jpeg', 0.82)
}

import LZString from 'lz-string';

export interface PuzzleData {
    id?: string;
    pw?: string | null;
    title: string;
    thumb: string;
    cols: number;
    rows: number;
    grid: number[][]; // actual answer grid 0/1
    rowClues: number[][];
    colClues: number[][];
    diffIdx: number;
    logicDiff: string;
}

export function encodePuzzle(data: PuzzleData): string {
    return LZString.compressToEncodedURIComponent(JSON.stringify(data));
}

export function decodePuzzle(encoded: string): PuzzleData | null {
    try {
        const decompressed = LZString.decompressFromEncodedURIComponent(encoded);
        if (!decompressed) return null;
        const data = JSON.parse(decompressed);
        if (!data || !data.grid || !Array.isArray(data.grid)) return null;
        return data as PuzzleData;
    } catch (e) {
        return null;
    }
}
